## Core Insight

OmniLottie introduces a novel approach to vector animation generation by leveraging parameterized Lottie tokens. Rather than requiring manual design or complex animation software, the system enables direct generation of Lottie JSON animations through a token-based representation. This approach treats animation generation as a sequence prediction problem, where each token encodes specific animation parameters (keyframe positions, timing, shape properties, color transitions). The parameterized token space provides a compact, learnable representation that maps from high-level descriptions to executable animation specifications.

## Implementation

```python
import json
import math
from typing import List, Dict, Tuple, Any
from dataclasses import dataclass
from enum import Enum

class AnimationPropertyType(Enum):
    POSITION = "position"
    OPACITY = "opacity"
    ROTATION = "rotation"
    SCALE = "scale"
    COLOR = "color"

@dataclass
class KeyFrame:
    time: float
    value: Any
    ease_in: float = 0.25
    ease_out: float = 0.75

@dataclass
class AnimationProperty:
    property_type: AnimationPropertyType
    keyframes: List[KeyFrame]

class LottieTokenGenerator:
    def __init__(self, width: int = 512, height: int = 512, frame_rate: int = 24):
        self.width = width
        self.height = height
        self.frame_rate = frame_rate
        self.layers = []
        self.compositions = []

    def create_shape_layer(self, name: str, shape_type: str) -> Dict:
        """Create a shape layer with specified geometry."""
        return {
            "ty": 4,  # Shape layer type
            "nm": name,
            "shapes": [self._create_shape(shape_type)]
        }

    def _create_shape(self, shape_type: str) -> Dict:
        """Generate shape definition based on type."""
        if shape_type == "rect":
            return {
                "ty": "rc",
                "d": 1,
                "s": {"k": [100, 100]},
                "p": {"k": [0, 0]}
            }
        elif shape_type == "circle":
            return {
                "ty": "el",
                "d": 1,
                "s": {"k": [100, 100]},
                "p": {"k": [0, 0]}
            }
        elif shape_type == "star":
            return {
                "ty": "sr",
                "d": 1,
                "ir": {"k": 50},
                "or": {"k": 100},
                "pt": {"k": 5}
            }
        return {}

    def add_position_animation(self, layer_idx: int, keyframes: List[Tuple[float, List[float]]]):
        """Add position animation keyframes to a layer."""
        kf_data = []
        for time, position in keyframes:
            kf_data.append({
                "t": time * self.frame_rate,
                "s": position,
                "e": position,
                "i": {"x": [0.25], "y": [0.25]},
                "o": {"x": [0.75], "y": [0.75]}
            })

        if layer_idx < len(self.layers):
            self.layers[layer_idx]["ao"] = 1
            # Store animation data for composition
            return kf_data

    def add_opacity_animation(self, layer_idx: int, keyframes: List[Tuple[float, float]]):
        """Add opacity animation keyframes to a layer."""
        kf_data = []
        for time, opacity in keyframes:
            kf_data.append({
                "t": time * self.frame_rate,
                "s": [opacity * 100],
                "e": [opacity * 100],
                "i": {"x": [0.25], "y": [0.25]},
                "o": {"x": [0.75], "y": [0.75]}
            })
        return kf_data

    def add_rotation_animation(self, layer_idx: int, keyframes: List[Tuple[float, float]]):
        """Add rotation animation keyframes to a layer."""
        kf_data = []
        for time, rotation in keyframes:
            kf_data.append({
                "t": time * self.frame_rate,
                "s": [rotation],
                "e": [rotation],
                "i": {"x": [0.25], "y": [0.25]},
                "o": {"x": [0.75], "y": [0.75]}
            })
        return kf_data

    def add_scale_animation(self, layer_idx: int, keyframes: List[Tuple[float, float]]):
        """Add scale animation keyframes to a layer."""
        kf_data = []
        for time, scale in keyframes:
            kf_data.append({
                "t": time * self.frame_rate,
                "s": [scale * 100, scale * 100],
                "e": [scale * 100, scale * 100],
                "i": {"x": [0.25], "y": [0.25]},
                "o": {"x": [0.75], "y": [0.75]}
            })
        return kf_data

    def add_color_animation(self, layer_idx: int, keyframes: List[Tuple[float, Tuple[float, float, float]]]):
        """Add color animation keyframes to a layer."""
        kf_data = []
        for time, color in keyframes:
            kf_data.append({
                "t": time * self.frame_rate,
                "s": list(color),
                "e": list(color),
                "i": {"x": [0.25], "y": [0.25]},
                "o": {"x": [0.75], "y": [0.75]}
            })
        return kf_data

    def generate_lottie_json(self, duration: float) -> Dict:
        """Generate complete Lottie animation JSON."""
        return {
            "v": "5.9.0",
            "fr": self.frame_rate,
            "ip": 0,
            "op": int(duration * self.frame_rate),
            "w": self.width,
            "h": self.height,
            "layers": self.layers,
            "assets": [],
            "comps": self.compositions
        }

    def export(self, filepath: str, duration: float = 2.0):
        """Export animation to Lottie JSON file."""
        lottie_json = self.generate_lottie_json(duration)
        with open(filepath, 'w') as f:
            json.dump(lottie_json, f, indent=2)

class ParameterizedTokenDecoder:
    """Decode parameterized animation tokens into executable animations."""

    def __init__(self):
        self.token_vocabulary = self._build_vocabulary()

    def _build_vocabulary(self) -> Dict[str, int]:
        """Build mapping of animation tokens to parameter indices."""
        return {
            "MOVE": 0, "ROTATE": 1, "SCALE": 2, "FADE": 3,
            "COLOR": 4, "BOUNCE": 5, "EASE_IN": 6, "EASE_OUT": 7,
            "LINEAR": 8, "CURVE": 9, "LOOP": 10, "REVERSE": 11
        }

    def decode_tokens(self, tokens: List[str]) -> List[AnimationProperty]:
        """Convert token sequence to animation properties."""
        properties = []
        i = 0
        while i < len(tokens):
            token = tokens[i]
            if token == "MOVE":
                duration = float(tokens[i+1]) if i+1 < len(tokens) else 1.0
                properties.append(
                    AnimationProperty(
                        AnimationPropertyType.POSITION,
                        [KeyFrame(0, [0, 0]), KeyFrame(duration, [100, 100])]
                    )
                )
                i += 2
            elif token == "FADE":
                duration = float(tokens[i+1]) if i+1 < len(tokens) else 1.0
                properties.append(
                    AnimationProperty(
                        AnimationPropertyType.OPACITY,
                        [KeyFrame(0, 1.0), KeyFrame(duration, 0.0)]
                    )
                )
                i += 2
            else:
                i += 1
        return properties

# Example usage
if __name__ == "__main__":
    generator = LottieTokenGenerator(width=512, height=512)

    # Create a simple bouncing ball animation
    ball_layer = generator.create_shape_layer("ball", "circle")
    generator.layers.append(ball_layer)

    # Add position keyframes for bouncing motion
    position_keyframes = [
        (0.0, [256, 300]),
        (0.5, [256, 100]),
        (1.0, [256, 300]),
    ]
    generator.add_position_animation(0, position_keyframes)

    # Add opacity animation
    opacity_keyframes = [
        (0.0, 1.0),
        (1.0, 1.0),
    ]
    generator.add_opacity_animation(0, opacity_keyframes)

    # Export animation
    generator.export("animation.json", duration=2.0)
```

## Practical Guidance

1. **Understand the Token Space**: Familiarize yourself with the parameterized token vocabulary—each token encodes a specific animation property (position, rotation, opacity, scale, color). Learn how combinations of tokens produce complex animations.

2. **Start with Simple Animations**: Begin by generating basic animations like movement, fading, or rotation before combining multiple properties. This helps you understand how parameters interact.

3. **Optimize Frame Rates and Duration**: Choose appropriate frame rates (typically 24-60 fps) and animation durations based on your use case. Lower frame rates reduce file size; higher rates provide smoother motion.

4. **Use Keyframe Interpolation**: Leverage easing functions (ease-in, ease-out, linear, cubic) to create natural-looking motion. Avoid sudden jumps between keyframes unless intentional.

5. **Layer Management**: Organize complex animations into multiple layers (shapes, text, effects). Stack layers strategically to create depth and visual interest.

6. **Batch Generation**: When creating multiple animations, generate tokens in batches and cache the Lottie JSON outputs to reduce computational overhead.

7. **Validate JSON Output**: Always validate generated Lottie JSON against the Lottie specification to ensure compatibility with target platforms (web, mobile, desktop).

8. **Performance Testing**: Test animations on target devices/browsers for performance. Complex animations with many layers or keyframes may impact rendering performance.

